/bin/zsh -lc "python - <<'PY'
import csv, json
from decimal import Decimal, ROUND_HALF_UP
ZONE_RATE = {
    \"same_city\": 5, \"same_province\": 8,
    \"adjacent\": 12, \"remote\": 18,
}

def b(v):
    return str(v).strip().lower() == 'true'

def calc_shipping(pkg):
    vol_weight = pkg['length'] * pkg['width'] * pkg['height'] / 6000
    billable = max(pkg['actual_weight'], vol_weight)
    base = ZONE_RATE[pkg['zone']]
    if billable <= 1:
        cost = base
    else:
        cost = base + (billable - 1) * base * 0.6
    mult = 1.0
    if pkg.get('fragile'):
        mult += 0.15
    if any(d > 100 for d in [pkg['length'], pkg['width'], pkg['height']]):
        mult += 0.25
    if pkg.get('cold_chain'):
        mult += 0.30
    cost *= mult
    if pkg.get('vip'):
        cost *= 0.9
    return round(max(cost, 10), 1)

out=[]
with open('input.csv', newline='') as f:
    for row in csv.DictReader(f):
        pkg = {
            'actual_weight': float(row['actual_weight']),
            'length': float(row['length']),
            'width': float(row['width']),
            'height': float(row['height']),
            'zone': row['zone'],
            'fragile': b(row['fragile']),
            'cold_chain': b(row['cold_chain']),
            'vip': b(row['vip']),
        }
        out.append({'id': row['id'], 'cost': calc_shipping(pkg)})
print(json.dumps(out, indent=2, ensure_ascii=False))
